import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';

export async function PATCH\(
  request: NextRequest,
  { params }: { params: { id: string } }
\) {
  try {
    const { id } = params;
    const body = await request.json\(\);
    const { type } = body; // 'view', 'download', or 'share'

    if \(!['view', 'download', 'share'].includes\(type\)\) {
      return NextResponse.json\(
        { success: false, error: 'Invalid stat type' },
        { status: 400 }
      \);
    }

    // Update the corresponding stat
    const updateData: any = {};
    if \(type === 'view'\) {
      updateData.views = { increment: 1 };
    } else if \(type === 'download'\) {
      updateData.downloads = { increment: 1 };
    } else if \(type === 'share'\) {
      updateData.shares = { increment: 1 };
    }

    const invitation = await prisma.invitation.update\({
      where: { id },
      data: updateData,
      select: {
        id: true,
        views: true,
        downloads: true,
        shares: true,
      },
    }\);

    return NextResponse.json\({
      success: true,
      data: invitation,
    }\);
  } catch \(error\) {
    console.error\('Error updating stats:', error\);
    return NextResponse.json\(
      { success: false, error: 'Failed to update stats' },
      { status: 500 }
    \);
  }
}

export async function GET\(
  request: NextRequest,
  { params }: { params: { id: string } }
\) {
  try {
    const { id } = params;

    const invitation = await prisma.invitation.findUnique\({
      where: { id },
      select: {
        id: true,
        views: true,
        downloads: true,
        shares: true,
        createdAt: true,
      },
    }\);

    if \(!invitation\) {
      return NextResponse.json\(
        { success: false, error: 'Invitation not found' },
        { status: 404 }
      \);
    }

    return NextResponse.json\({
      success: true,
      data: invitation,
    }\);
  } catch \(error\) {
    console.error\('Error fetching stats:', error\);
    return NextResponse.json\(
      { success: false, error: 'Failed to fetch stats' },
      { status: 500 }
    \);
  }
}
EOF)
